        string(name: 'TARGET_SERVER_USER', defaultValue: 'deployuser', description: 'Username for SSH connection to target servers.')
        string(name: 'TARGET_SERVER_KEY_CREDENTIAL_ID', defaultValue: 'prod-ssh-key', description: 'Jenkins credential ID for the SSH private key to connect to target servers.')
        string(name: 'DEPLOY_PATH', defaultValue: '/opt/app/deploy', description: 'Absolute path on target servers where artifacts will be deployed.')
        text(name: 'PRE_DEPLOY_COMMANDS', defaultValue: '# Example: sudo systemctl stop myapp\n# Example: sudo rm -rf /opt/app/deploy/*', description: 'Multi-line commands to execute on target servers BEFORE deployment (e.g., stop service, clean old files).')
        text(name: 'POST_DEPLOY_COMMANDS', defaultValue: '# Example: sudo systemctl start myapp\n# Example: sudo chown -R myapp:myapp /opt/app/deploy', description: 'Multi-line commands to execute on target servers AFTER deployment (e.g., start service, set permissions).')
